  height: 100vh !important;
  border-radius: 0;
  border: none;
  left: 0 !important;
  top: 0 !important;
}

/* ═══ Top bar ═══ */
.panel-top {
  display: flex;
  align-items: center;
  padding: 10px 14px;
  border-bottom: 1px solid rgba(255,255,255,0.06);
  background: rgba(15,23,42,0.5);
  gap: 8px;
  cursor: grab;
  user-select: none;
  touch-action: none;
  flex-shrink: 0;
}
.mobile .panel-top { cursor: default; padding: 14px 16px; }
.panel-top.dragging { cursor: grabbing; }

.panel-title {
  font-size: 13px;
  font-weight: 600;
  white-space: nowrap;
}
.panel-preset {
  font-size: 11px;
  color: rgba(255,255,255,0.3);
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.btn-icon {
  width: 28px;
