  padding: 5px 14px;
  font-size: 12px;
  font-weight: 500;
  border: none;
  background: rgba(255,255,255,0.02);
  color: rgba(255,255,255,0.4);
  cursor: pointer;
  transition: all .15s;
}
.model-btn:first-child { border-right: 1px solid rgba(255,255,255,0.06); }
.model-btn:hover { background: rgba(255,255,255,0.06); color: rgba(255,255,255,0.7); }
.model-btn.active {
